module top_module(
  input                clk,
  input                rst_n,
  output reg  [3:0]    Q
);reg [63:0] feedback_reg;
  wire [63:0] xor_output;

  assign xor_output = feedback_reg ^ ({feedback_reg[0], feedback_reg[63:1]});

  always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
      feedback_reg <= 64'h0000000000000000;
      Q <= 4'b0000;
    end
    else begin
      feedback_reg <= {feedback_reg[62:0], xor_output[0]};
      Q <= {feedback_reg[1], feedback_reg[0]};
    end
  end

endmodule
